--
-- Intro to Postgres - Series 02 Sample Data
--
-- This file creates and populates the users and orders tables
-- for learning basic SQL queries, joins, and aggregations.
--
-- Usage: Run this file in any SQL client (TablePlus, pgAdmin, etc.)
--

-- Clean up if tables exist (in correct order due to foreign key)
DROP TABLE IF EXISTS orders CASCADE;
DROP TABLE IF EXISTS users CASCADE;

--
-- Users table
--

CREATE TABLE users (
    id bigint NOT NULL,
    name character varying(255),
    username character varying(255) NOT NULL,
    email character varying(255) NOT NULL,
    phone character varying(255),
    status character varying(255) NOT NULL,
    country character varying(255) NOT NULL,
    email_verified_at timestamp(0) without time zone,
    deleted_at timestamp(0) without time zone,
    created_at timestamp(0) without time zone,
    updated_at timestamp(0) without time zone
);

CREATE SEQUENCE users_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;

ALTER SEQUENCE users_id_seq OWNED BY users.id;
ALTER TABLE ONLY users ALTER COLUMN id SET DEFAULT nextval('users_id_seq'::regclass);

--
-- Orders table
--

CREATE TABLE orders (
    id bigint NOT NULL,
    customer_id bigint NOT NULL,
    price numeric(10,2) NOT NULL,
    discount numeric(10,2),
    total numeric(10,2),
    shipping_country character varying(255) NOT NULL,
    region character varying(255) NOT NULL,
    category character varying(255) NOT NULL,
    product_id bigint NOT NULL,
    created_at timestamp(0) without time zone,
    updated_at timestamp(0) without time zone
);

CREATE SEQUENCE orders_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;

ALTER SEQUENCE orders_id_seq OWNED BY orders.id;
ALTER TABLE ONLY orders ALTER COLUMN id SET DEFAULT nextval('orders_id_seq'::regclass);

--

--
-- Users data
--


--
-- Orders data
--


SELECT setval('users_id_seq', (SELECT MAX(id) FROM users), true);
SELECT setval('orders_id_seq', (SELECT MAX(id) FROM orders), true);

--
-- Primary keys
--

ALTER TABLE ONLY users
    ADD CONSTRAINT users_pkey PRIMARY KEY (id);

ALTER TABLE ONLY orders
    ADD CONSTRAINT orders_pkey PRIMARY KEY (id);

--
-- Foreign keys
--

ALTER TABLE ONLY orders
    ADD CONSTRAINT orders_customer_id_foreign FOREIGN KEY (customer_id) REFERENCES users(id);

--
-- Indexes
--

CREATE INDEX users_country_index ON users USING btree (country);
CREATE INDEX users_created_at_index ON users USING btree (created_at);
CREATE INDEX users_deleted_at_index ON users USING btree (deleted_at);
CREATE INDEX users_status_index ON users USING btree (status);

CREATE INDEX orders_category_index ON orders USING btree (category);
CREATE INDEX orders_created_at_index ON orders USING btree (created_at);
CREATE INDEX orders_customer_id_index ON orders USING btree (customer_id);
CREATE INDEX orders_product_id_index ON orders USING btree (product_id);
CREATE INDEX orders_region_index ON orders USING btree (region);
